import{_ as a,o as r,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 20260501","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260501.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260501.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_20260501.md"};function s(l,e,i,c,h,m){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="🫘-黃豆追蹤日誌-—-20260501" tabindex="-1">🫘 黃豆追蹤日誌 — 20260501 <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-20260501" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 20260501&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-01 Asia/Taipei 21:20 搜尋工具：web_search (Google Search grounding)</p></blockquote><hr><h2 id="📋-8-項追蹤指標" tabindex="-1">📋 8 項追蹤指標 <a class="header-anchor" href="#📋-8-項追蹤指標" aria-label="Permalink to &quot;📋 8 項追蹤指標&quot;">​</a></h2><h3 id="_1-現貨價" tabindex="-1">1. 現貨價 <a class="header-anchor" href="#_1-現貨價" aria-label="Permalink to &quot;1. 現貨價&quot;">​</a></h3><p><strong>1,185.53 美分/蒲式耳</strong>（5/1，+0.30%）。月漲 1.89%，年漲 13.04%。 <em>來源：TradingEconomics — <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></em></p><h3 id="_2-期貨價-近月-遠月" tabindex="-1">2. 期貨價（近月/遠月） <a class="header-anchor" href="#_2-期貨價-近月-遠月" aria-label="Permalink to &quot;2. 期貨價（近月/遠月）&quot;">​</a></h3><ul><li>近月 CBOT 5 月（ZSK26）4/30 收 <strong>$11.82¼</strong></li><li>遠月 7 月期貨：1,190+ 美分</li><li>12 個月預測：<strong>1,225.89 美分</strong>（TradingEconomics） <em>來源：CME Group — <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html</a>, TradingEconomics</em></li></ul><h3 id="_3-技術線-ma20-ma60" tabindex="-1">3. 技術線（MA20/MA60） <a class="header-anchor" href="#_3-技術線-ma20-ma60" aria-label="Permalink to &quot;3. 技術線（MA20/MA60）&quot;">​</a></h3><ul><li>價格 1,185 高於 MA20 和 MA60，短中期均線多頭排列</li><li>4 週漲 1.69%，六週新高動能持續</li><li>關鍵阻力：1,200 美分（觸發閾值）</li><li>關鍵支撐：1,150 美分 <em>來源：TradingEconomics — <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></em></li></ul><h3 id="_4-庫存數據" tabindex="-1">4. 庫存數據 <a class="header-anchor" href="#_4-庫存數據" aria-label="Permalink to &quot;4. 庫存數據&quot;">​</a></h3><ul><li>2025/26 年度巴西庫存充裕（產量 1.778-1.781 億噸創紀錄）</li><li>阿根廷收割延遲（聖塔菲省僅 10% 完成 vs 季節平均 60%），供應暫時偏緊 <em>來源：Kpler — <a href="https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge" target="_blank" rel="noreferrer">https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge</a></em></li></ul><h3 id="_5-出口銷售" tabindex="-1">5. 出口銷售 <a class="header-anchor" href="#_5-出口銷售" aria-label="Permalink to &quot;5. 出口銷售&quot;">​</a></h3><ul><li>USDA 4/30 出口銷售報告：截至 4/23 週出口 <strong>261,100 噸</strong>（2025/26 + 2026/27 年度）</li><li><strong>258,066 噸</strong>為年度次低。中國為最大買家。新作銷售僅 2,980 噸。 <em>來源：Morningstar — <a href="https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts" target="_blank" rel="noreferrer">https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts</a>, Barchart</em></li></ul><h3 id="_6-天氣狀況" tabindex="-1">6. 天氣狀況 <a class="header-anchor" href="#_6-天氣狀況" aria-label="Permalink to &quot;6. 天氣狀況&quot;">​</a></h3><ul><li>🇺🇸 <strong>美國</strong>：截至 4/26 已種植 23%（五年均 12%）。廣幅降雨將擾亂田間作業。西部和南部農業帶部分地區乾旱。</li><li>🇧🇷 <strong>巴西</strong>：南里奧格蘭德州降雨低於平均，影響產量潛力。但整體 2025/26 產量仍創紀錄。</li><li>🇦🇷 <strong>阿根廷</strong>：聖塔菲省持續降雨導致收割僅 10%（季節平均 60%）。水分不足影響生殖期作物。 <em>來源：AgWeb — <a href="https://www.agweb.com/weather" target="_blank" rel="noreferrer">https://www.agweb.com/weather</a>, Kpler — <a href="https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge" target="_blank" rel="noreferrer">https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge</a></em></li></ul><h3 id="_7-美元指數影響" tabindex="-1">7. 美元指數影響 <a class="header-anchor" href="#_7-美元指數影響" aria-label="Permalink to &quot;7. 美元指數影響&quot;">​</a></h3><p>DXY <strong>98.11</strong>（5/1，+0.05%），月跌 1.88%。美元走弱對黃豆價格構成支撐。 <em>來源：Investing.com — <a href="https://www.investing.com/indices/usdollar" target="_blank" rel="noreferrer">https://www.investing.com/indices/usdollar</a>, TradingEconomics</em></p><h3 id="_8-基金淨持倉" tabindex="-1">8. 基金淨持倉 <a class="header-anchor" href="#_8-基金淨持倉" aria-label="Permalink to &quot;8. 基金淨持倉&quot;">​</a></h3><p>CFTC 截至 4/24 投機淨多頭 <strong>211.1K</strong>。截至 4/20 基金連續第二週削減主要農產品期貨淨多頭。 <em>來源：CFTC via MQL5 — <a href="https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions" target="_blank" rel="noreferrer">https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions</a></em></p><hr><h2 id="🗞️-5-條黃豆相關新聞" tabindex="-1">🗞️ 5 條黃豆相關新聞 <a class="header-anchor" href="#🗞️-5-條黃豆相關新聞" aria-label="Permalink to &quot;🗞️ 5 條黃豆相關新聞&quot;">​</a></h2><h3 id="新聞-1-cbot-黃豆期貨六週新高-生質燃料需求推升" tabindex="-1">新聞 1：CBOT 黃豆期貨六週新高，生質燃料需求推升 <a class="header-anchor" href="#新聞-1-cbot-黃豆期貨六週新高-生質燃料需求推升" aria-label="Permalink to &quot;新聞 1：CBOT 黃豆期貨六週新高，生質燃料需求推升&quot;">​</a></h3><p>5/1 黃豆升至 1,185.53 美分（+0.30%），創六週新高。阿根廷收割延遲、生質燃料強制令和油價高檔推升植物油需求為主要驅動力。 <em>來源：TradingEconomics — <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></em></p><h3 id="新聞-2-巴西-2025-26-產量預估-1-78-1-79-億噸創紀錄" tabindex="-1">新聞 2：巴西 2025/26 產量預估 1.78-1.79 億噸創紀錄 <a class="header-anchor" href="#新聞-2-巴西-2025-26-產量預估-1-78-1-79-億噸創紀錄" aria-label="Permalink to &quot;新聞 2：巴西 2025/26 產量預估 1.78-1.79 億噸創紀錄&quot;">​</a></h3><p>Conab 預測 1.7785 億噸，Safras &amp; Mercado 預測 1.7811 億噸。種植面積約 4,900 萬公頃創新高。但農民利潤率受低價和高成本擠壓，均價從 $440 下修至 $370/噸。 <em>來源：farmdocdaily Illinois — <a href="https://farmdocdaily.illinois.edu/2026/03/brazil-heads-for-a-record-soybean-harvest-as-farm-margins-approach-breakeven.html" target="_blank" rel="noreferrer">https://farmdocdaily.illinois.edu/2026/03/brazil-heads-for-a-record-soybean-harvest-as-farm-margins-approach-breakeven.html</a>, Agrolatam</em></p><h3 id="新聞-3-阿根廷產量上修至-4-860-萬噸" tabindex="-1">新聞 3：阿根廷產量上修至 4,860 萬噸 <a class="header-anchor" href="#新聞-3-阿根廷產量上修至-4-860-萬噸" aria-label="Permalink to &quot;新聞 3：阿根廷產量上修至 4,860 萬噸&quot;">​</a></h3><p>布宜諾斯艾利斯穀物交易所上調至 4,860 萬噸優於預期。但聖塔菲省持續降雨嚴重影響收割進度（僅 10% 完成）。 <em>來源：AgroReview, Kpler — <a href="https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge" target="_blank" rel="noreferrer">https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge</a></em></p><h3 id="新聞-4-usda-出口銷售低迷-年度次低" tabindex="-1">新聞 4：USDA 出口銷售低迷，年度次低 <a class="header-anchor" href="#新聞-4-usda-出口銷售低迷-年度次低" aria-label="Permalink to &quot;新聞 4：USDA 出口銷售低迷，年度次低&quot;">​</a></h3><p>4/30 報告顯示出口 258,066 噸（年度次低），新作僅 2,980 噸。中國雖為最大買家但採購量明顯放緩，反映中美貿易不確定性。 <em>來源：Morningstar — <a href="https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts" target="_blank" rel="noreferrer">https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts</a></em></p><h3 id="新聞-5-荷莫茲封閉推升肥料成本-農民轉向黃豆種植" tabindex="-1">新聞 5：荷莫茲封閉推升肥料成本，農民轉向黃豆種植 <a class="header-anchor" href="#新聞-5-荷莫茲封閉推升肥料成本-農民轉向黃豆種植" aria-label="Permalink to &quot;新聞 5：荷莫茲封閉推升肥料成本，農民轉向黃豆種植&quot;">​</a></h3><p>荷莫茲封閉影響全球 40% 尿素出口。尿素價格曾飆至 $866/噸（4 月高點）。高肥料成本使美國農民從玉米轉向自行固氮的黃豆（黃豆面積 +4% vs 玉米 -3%）。 <em>來源：World Bank, Metals Hub — <a href="https://www.metals-hub.com/en/blog/urea-market-in-2026/" target="_blank" rel="noreferrer">https://www.metals-hub.com/en/blog/urea-market-in-2026/</a></em></p><hr><h2 id="📚-資料來源-全" tabindex="-1">📚 資料來源（全） <a class="header-anchor" href="#📚-資料來源-全" aria-label="Permalink to &quot;📚 資料來源（全）&quot;">​</a></h2><ol><li>TradingEconomics Soybean: <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></li><li>CME Group: <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html</a></li><li>CFTC Non-Commercial Net Positions via MQL5: <a href="https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions" target="_blank" rel="noreferrer">https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions</a></li><li>USDA Export Sales (Morningstar): <a href="https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts" target="_blank" rel="noreferrer">https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts</a></li><li>Kpler South America Weather: <a href="https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge" target="_blank" rel="noreferrer">https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge</a></li><li>AgWeb Weather: <a href="https://www.agweb.com/weather" target="_blank" rel="noreferrer">https://www.agweb.com/weather</a></li><li>Investing.com DXY: <a href="https://www.investing.com/indices/usdollar" target="_blank" rel="noreferrer">https://www.investing.com/indices/usdollar</a></li><li>farmdocdaily Illinois: <a href="https://farmdocdaily.illinois.edu/2026/03/brazil-heads-for-a-record-soybean-harvest-as-farm-margins-approach-breakeven.html" target="_blank" rel="noreferrer">https://farmdocdaily.illinois.edu/2026/03/brazil-heads-for-a-record-soybean-harvest-as-farm-margins-approach-breakeven.html</a></li><li>Agrolatam Brazil Record: <a href="https://www.agrolatam.com/news/brazil-soybean-exports-2026-record-revenue-argentina-growth/" target="_blank" rel="noreferrer">https://www.agrolatam.com/news/brazil-soybean-exports-2026-record-revenue-argentina-growth/</a></li><li>Metals Hub Urea: <a href="https://www.metals-hub.com/en/blog/urea-market-in-2026/" target="_blank" rel="noreferrer">https://www.metals-hub.com/en/blog/urea-market-in-2026/</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-01 Asia/Taipei 21:20</em></p>',37)])])}const w=a(n,[["render",s]]);export{p as __pageData,w as default};
